import React, { useState, useRef, useEffect } from "react";
import { createRoot } from "react-dom/client";
import { GoogleGenAI } from "@google/genai";
import ReactMarkdown from "react-markdown";
import { Send, Image as ImageIcon, Loader2, X } from "lucide-react";

// Initialize Gemini AI
const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

// Types
type Message = {
  id: string;
  role: "user" | "model";
  text: string;
  image?: string; // Base64 string for display and API
  isStreaming?: boolean;
};

// Styles
const styles = {
  container: {
    maxWidth: "800px",
    margin: "0 auto",
    height: "100vh",
    display: "flex",
    flexDirection: "column" as const,
    backgroundColor: "#ffffff",
    boxShadow: "0 0 20px rgba(0,0,0,0.05)",
  },
  header: {
    padding: "20px",
    borderBottom: "1px solid #e5e7eb",
    display: "flex",
    alignItems: "center",
    justifyContent: "space-between",
    backgroundColor: "#fff",
  },
  title: {
    margin: 0,
    fontSize: "1.25rem",
    fontWeight: 600,
    color: "#111827",
    display: "flex",
    alignItems: "center",
    gap: "8px",
  },
  messages: {
    flex: 1,
    overflowY: "auto" as const,
    padding: "20px",
    display: "flex",
    flexDirection: "column" as const,
    gap: "24px",
  },
  messageRow: (role: "user" | "model") => ({
    display: "flex",
    justifyContent: role === "user" ? "flex-end" : "flex-start",
  }),
  messageBubble: (role: "user" | "model") => ({
    maxWidth: "80%",
    padding: "12px 16px",
    borderRadius: "16px",
    borderTopRightRadius: role === "user" ? "4px" : "16px",
    borderTopLeftRadius: role === "model" ? "4px" : "16px",
    backgroundColor: role === "user" ? "#2563eb" : "#f3f4f6",
    color: role === "user" ? "#ffffff" : "#1f2937",
    lineHeight: 1.5,
    fontSize: "0.95rem",
  }),
  inputContainer: {
    padding: "20px",
    borderTop: "1px solid #e5e7eb",
    backgroundColor: "#fff",
  },
  inputWrapper: {
    display: "flex",
    flexDirection: "column" as const,
    gap: "12px",
    border: "1px solid #e5e7eb",
    borderRadius: "12px",
    padding: "12px",
    transition: "border-color 0.2s",
  },
  previewContainer: {
    display: "flex",
    gap: "8px",
    flexWrap: "wrap" as const,
  },
  previewItem: {
    position: "relative" as const,
    width: "60px",
    height: "60px",
    borderRadius: "8px",
    overflow: "hidden",
    border: "1px solid #e5e7eb",
  },
  previewImage: {
    width: "100%",
    height: "100%",
    objectFit: "cover" as const,
  },
  removeButton: {
    position: "absolute" as const,
    top: "2px",
    right: "2px",
    background: "rgba(0,0,0,0.5)",
    color: "white",
    border: "none",
    borderRadius: "50%",
    width: "16px",
    height: "16px",
    display: "flex",
    alignItems: "center",
    justifyContent: "center",
    cursor: "pointer",
    padding: 0,
  },
  controls: {
    display: "flex",
    gap: "12px",
    alignItems: "flex-end",
  },
  textarea: {
    flex: 1,
    border: "none",
    resize: "none" as const,
    outline: "none",
    padding: "8px 0",
    fontFamily: "inherit",
    fontSize: "0.95rem",
    maxHeight: "150px",
    minHeight: "24px",
  },
  iconButton: {
    background: "none",
    border: "none",
    cursor: "pointer",
    color: "#6b7280",
    padding: "8px",
    borderRadius: "8px",
    display: "flex",
    alignItems: "center",
    justifyContent: "center",
    transition: "background-color 0.2s",
  },
  sendButton: (disabled: boolean) => ({
    background: disabled ? "#e5e7eb" : "#2563eb",
    color: "#fff",
    border: "none",
    borderRadius: "8px",
    padding: "8px 16px",
    cursor: disabled ? "not-allowed" : "pointer",
    display: "flex",
    alignItems: "center",
    gap: "6px",
    fontWeight: 500,
    transition: "background-color 0.2s",
  }),
  imageMessage: {
    maxWidth: "300px",
    borderRadius: "8px",
    marginBottom: "8px",
    display: "block",
  },
};

const App = () => {
  const [messages, setMessages] = useState<Message[]>([]);
  const [inputValue, setInputValue] = useState("");
  const [selectedImage, setSelectedImage] = useState<string | null>(null);
  const [isStreaming, setIsStreaming] = useState(false);
  const messagesEndRef = useRef<HTMLDivElement>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
  };

  useEffect(() => {
    scrollToBottom();
  }, [messages]);

  const handleImageSelect = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setSelectedImage(reader.result as string);
      };
      reader.readAsDataURL(file);
    }
  };

  const handleSend = async () => {
    if ((!inputValue.trim() && !selectedImage) || isStreaming) return;

    const userMessage: Message = {
      id: Date.now().toString(),
      role: "user",
      text: inputValue,
      image: selectedImage || undefined,
    };

    setMessages((prev) => [...prev, userMessage]);
    setInputValue("");
    setSelectedImage(null);
    setIsStreaming(true);

    try {
      const history = messages.map((m) => {
        const parts: any[] = [];
        if (m.image) {
          parts.push({
            inlineData: {
              mimeType: "image/jpeg", // Assuming jpeg for simplicity or extract from base64
              data: m.image.split(",")[1],
            },
          });
        }
        if (m.text) {
          parts.push({ text: m.text });
        }
        return {
          role: m.role,
          parts: parts,
        };
      });

      // Add current message to history for the API call
      const currentParts: any[] = [];
      if (userMessage.image) {
        currentParts.push({
          inlineData: {
            mimeType: "image/jpeg",
            data: userMessage.image.split(",")[1],
          },
        });
      }
      if (userMessage.text) {
        currentParts.push({ text: userMessage.text });
      }

      // We use generateContentStream for single turn or manually managed history
      // Note: 'contents' can be an array for multi-turn history.
      const contents = [
        ...history,
        { role: "user", parts: currentParts },
      ];

      const result = await ai.models.generateContentStream({
        model: "gemini-3-flash-preview",
        contents: contents,
      });

      const modelMessageId = (Date.now() + 1).toString();
      setMessages((prev) => [
        ...prev,
        { id: modelMessageId, role: "model", text: "", isStreaming: true },
      ]);

      let fullText = "";
      for await (const chunk of result) {
        const text = chunk.text;
        if (text) {
          fullText += text;
          setMessages((prev) =>
            prev.map((m) =>
              m.id === modelMessageId ? { ...m, text: fullText } : m
            )
          );
        }
      }

      setMessages((prev) =>
        prev.map((m) =>
          m.id === modelMessageId ? { ...m, isStreaming: false } : m
        )
      );
    } catch (error) {
      console.error("Error generating content:", error);
      setMessages((prev) => [
        ...prev,
        {
          id: Date.now().toString(),
          role: "model",
          text: "Sorry, I encountered an error. Please try again.",
        },
      ]);
    } finally {
      setIsStreaming(false);
    }
  };

  return (
    <div style={styles.container}>
      <header style={styles.header}>
        <h1 style={styles.title}>
          <span style={{ fontSize: "1.5rem" }}>✨</span> Gemini Chat
        </h1>
      </header>

      <div style={styles.messages}>
        {messages.length === 0 && (
          <div style={{ textAlign: "center", color: "#6b7280", marginTop: "40px" }}>
            <p>Say hello to start a conversation!</p>
          </div>
        )}
        {messages.map((msg) => (
          <div key={msg.id} style={styles.messageRow(msg.role)}>
            <div style={styles.messageBubble(msg.role)}>
              {msg.image && (
                <img src={msg.image} alt="User upload" style={styles.imageMessage} />
              )}
              {msg.role === "model" ? (
                <ReactMarkdown>{msg.text}</ReactMarkdown>
              ) : (
                <div style={{ whiteSpace: "pre-wrap" }}>{msg.text}</div>
              )}
            </div>
          </div>
        ))}
        {isStreaming && messages[messages.length - 1]?.role === "user" && (
            <div style={styles.messageRow("model")}>
                <div style={styles.messageBubble("model")}>
                     <Loader2 size={16} className="animate-spin" />
                </div>
            </div>
        )}
        <div ref={messagesEndRef} />
      </div>

      <div style={styles.inputContainer}>
        <div style={styles.inputWrapper}>
          {selectedImage && (
            <div style={styles.previewContainer}>
              <div style={styles.previewItem}>
                <img src={selectedImage} alt="Preview" style={styles.previewImage} />
                <button
                  onClick={() => setSelectedImage(null)}
                  style={styles.removeButton}
                >
                  <X size={10} />
                </button>
              </div>
            </div>
          )}
          <div style={styles.controls}>
            <button
              style={styles.iconButton}
              onClick={() => fileInputRef.current?.click()}
              title="Add image"
            >
              <ImageIcon size={20} />
            </button>
            <input
              type="file"
              ref={fileInputRef}
              onChange={handleImageSelect}
              accept="image/*"
              style={{ display: "none" }}
            />
            <textarea
              style={styles.textarea}
              value={inputValue}
              onChange={(e) => setInputValue(e.target.value)}
              onKeyDown={(e) => {
                if (e.key === "Enter" && !e.shiftKey) {
                  e.preventDefault();
                  handleSend();
                }
              }}
              placeholder="Type a message..."
              rows={1}
            />
            <button
              style={styles.sendButton(!inputValue.trim() && !selectedImage || isStreaming)}
              onClick={handleSend}
              disabled={(!inputValue.trim() && !selectedImage) || isStreaming}
            >
              {isStreaming ? (
                <Loader2 size={18} className="animate-spin" />
              ) : (
                <Send size={18} />
              )}
            </button>
          </div>
        </div>
      </div>
      <style>{`
        @keyframes spin {
          from { transform: rotate(0deg); }
          to { transform: rotate(360deg); }
        }
        .animate-spin {
          animation: spin 1s linear infinite;
        }
        p { margin-top: 0; margin-bottom: 0.5em; }
        p:last-child { margin-bottom: 0; }
        code { background: rgba(0,0,0,0.1); padding: 2px 4px; borderRadius: 4px; }
        pre { background: #1f2937; color: white; padding: 12px; borderRadius: 8px; overflow-x: auto; }
        pre code { background: none; color: inherit; padding: 0; }
      `}</style>
    </div>
  );
};

const root = createRoot(document.getElementById("root")!);
root.render(<App />);
